public function __invoke(Request $request, Export $export): StreamedResponse
    {
        abort_unless(auth(
            $request->hasValidSignature(absolute: false)
                ? $request->query('authGuard')
                : null,
        )->check(), 401);

        $user = auth(
            $request->hasValidSignature(absolute: false)
                ? $request->query('authGuard')
                : null,
        )->user();

        $exportPolicy = Gate::getPolicyFor($export::class);

        if (filled($exportPolicy) && method_exists($exportPolicy, 'view')) {
            Gate::forUser($user)->authorize('view', Arr::wrap($export));
        } else {
            abort_unless($export->user()->is($user), 403);
        }

        $format = $this->resolveFormatFromRequest($request);

        abort_unless($format !== null, 404);

        return $format->getDownloader()($export);
    }

public function getCustomBlocks(): ?array
    {
        if (blank($this->customBlocks)) {
            return null;
        }

        $blocks = [];

        foreach ($this->customBlocks as $key => $block) {
            if (is_string($key) && is_a($key, RichContentCustomBlock::class, allow_string: true)) {
                // Data association: `BlockClass::class => $data`
                $blocks[] = $key;
            } elseif (is_array($block)) {
                // Group or ungrouped section: `'Label' => [...]` or `[...]`
                foreach ($block as $innerKey => $innerValue) {
                    $blocks[] = is_string($innerKey) ? $innerKey : $innerValue;
                }
            } else {
                $blocks[] = $block;
            }
        }

        return $blocks;
    }

