public function handle(): int
    {
        try {
            $this->configureHasClusterClassesOutsideDirectories();
            $this->configureFqnEnd();
            $this->configurePanel(question: 'Which panel would you like to create this cluster in?');
            $this->configureClustersLocation();

            $this->configureFqn();

            $this->createClass();
        } catch (FailureCommandOutput) {
            return static::FAILURE;
        }

        $this->components->info("Filament cluster [{$this->fqn}] created successfully.");

        if (empty($this->panel->getClusterNamespaces())) {
            $this->components->info('Make sure to register the cluster with [clusters()] or discover it with [discoverClusters()] in the panel service provider.');
        }

        return static::SUCCESS;
    }

public function resolveRelativeKey(string | Component $key = '', bool $isAbsolute = false): string
    {
        if ($key instanceof Component) {
            return $key->getKey();
        }

        if (str($key)->startsWith('/')) {
            $isAbsolute = true;
            $key = (string) str($key)->after('/');
        }

        if ($isAbsolute) {
            return $key;
        }

        $containerKey = $this->getContainer()->getKey();

        while (str($key)->startsWith('../')) {
            $containerKey = Str::contains($containerKey, '.') ?
                (string) str($containerKey)->beforeLast('.') :
                null;

            $key = (string) str($key)->after('../');
        }

        if (blank($containerKey)) {
            return $key;
        }

        return filled(ltrim($key, './')) ? "{$containerKey}.{$key}" : $containerKey;
    }

protected function mapTableColumnToArray(Column $column): array
    {
        $label = e($column->getLabel());

        if (blank($label) && $this->hasReorderableTableColumns()) {
            throw new LogicException("The table column [{$column->getName()}] has a blank label. All columns must have labels when they are reorderable.");
        }

        return [
            'type' => self::TABLE_COLUMN_MANAGER_COLUMN_TYPE,
            'name' => $column->getName(),
            'label' => $label,
            'isHidden' => $column->isHidden(),
            'isToggled' => ! $column->isToggleable() || ! $column->isToggledHiddenByDefault(),
            'isToggleable' => $column->isToggleable(),
            'isToggledHiddenByDefault' => $column->isToggleable() ? $column->isToggledHiddenByDefault() : null,
        ];
    }

protected function setUp(): void
    {
        parent::setUp();

        $this->trueLabel(__('filament-forms::components.select.boolean.true'));
        $this->falseLabel(__('filament-forms::components.select.boolean.false'));
        $this->placeholder('-');

        $this->boolean();

        $this->indicateUsing(function (TernaryFilter $filter, array $state): array {
            if (blank($state['value'] ?? null)) {
                return [];
            }

            $stateLabel = $state['value'] ?
                $filter->getTrueLabel() :
                $filter->getFalseLabel();

            $indicator = $filter->getIndicator();

            if (! $indicator instanceof Indicator) {
                $indicator = Indicator::make("{$indicator}: {$stateLabel}");
            }

            return [$indicator];
        });
    }

